const NL = String.fromCharCode(10);
const N8N_KEY = 'REDACTED_JWT_TOKEN';
const BROAD_SCANNER_ID = '975pZZEtxeUbzI22';

const today = new Date().toISOString().substring(0, 10);

// Fetch recent Broad Scanner executions
const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://tradenextgen.app.n8n.cloud/api/v1/executions?workflowId=' + BROAD_SCANNER_ID + '&limit=20',
  headers: { 'X-N8N-API-KEY': N8N_KEY },
  json: true
});

let successToday = 0;
let errorsToday = 0;
let lastSuccess = 'never';

for (const e of (resp.data || [])) {
  if (!e.startedAt || !e.startedAt.startsWith(today)) continue;
  if (e.status === 'success') {
    successToday++;
    if (lastSuccess === 'never') lastSuccess = e.startedAt.substring(11, 19) + ' UTC';
  } else {
    errorsToday++;
  }
}

const healthy = successToday >= 3;

if (healthy) {
  // Silent success — do nothing
  return [];
}

// ALERT — scanner is down
const lines = [
  String.fromCharCode(128680) + ' <b>QUANTUM DEAD-MAN ALERT</b>',
  '',
  'Broad Scanner (Real-Time Agent) has <b>NOT</b> successfully evaluated any tickers since market open.',
  '',
  'Successes today: ' + successToday,
  'Errors today: ' + errorsToday,
  'Last successful run: ' + lastSuccess,
  '',
  '<i>Check n8n immediately.</i>'
];

return [{ json: { message: lines.join(NL) } }];
